$(document).ready(function(){window.filter=function(e=""){var i=$(".filter-form").serializeArray();$.ajax({url:BASE_URL+"/products/filter",method:"get",data:{attributes:i,filterBy:e},dataType:"json",success:function(t){t!=""?$(".product-list-section").html(t):$(".product-list-section").html("<p>No Data Found</p>")}})},window.ClearAll=function(){$(".filter-form")[0].reset(),filter()}});
